  'blog.post1.title':  { en: 'The Best Livingston Event Venue for Every Occasion', es: 'El Mejor Venue de Eventos en Livingston para Cada Ocasión' },
  'blog.post1.excerpt': { en: 'Most venues do one thing well. Inspira Ranch was built differently — 14 private acres in East Texas handling weddings, quinceañeras, corporate retreats, and milestone celebrations with equal care and a 5 star record.', es: 'La mayoría de los venues se especializan en una sola cosa. Inspira Ranch fue construido diferente — 14 acres privados en el Este de Texas para bodas, quinceañeras, retiros corporativos y celebraciones memorables, todos atendidos con el mismo nivel de excelencia.' },

  'blog.post2.title':   { en: 'Top Wedding Venues Near Houston, TX — Why Inspira Ranch Stands Out', es: 'Los Mejores Venues de Boda Cerca de Houston, TX — Por Qué Inspira Ranch Destaca' },
  'blog.post2.excerpt': { en: 'Most Houston-area wedding venues share one limitation: they\'re not truly private. Inspira Ranch offers 14 exclusive acres, an on-site chapel, horse and carriage, and a family team with a 5-star record — 50 minutes from Houston.', es: 'La mayoría de los venues de boda en el área de Houston comparten una limitación: no son verdaderamente privados. Inspira Ranch ofrece 14 acres exclusivos, capilla en el lugar, caballo y carreta, y un equipo familiar con historial de 5 estrellas — a 50 minutos de Houston.' },

  'blog.post3.title':   { en: 'The Best Quinceañera Venues in East Texas', es: 'Los Mejores Venues para Quinceañera en el Este de Texas' },
  'blog.post3.excerpt': { en: 'Planning a quinceañera near Houston or East Texas? Learn what separates a memorable celebration from an ordinary one — and why Inspira Ranch is the only venue in Livingston built for this milestone.', es: '¿Planeando una quinceañera cerca de Houston o en el Este de Texas? Descubre qué separa una celebración memorable de una ordinaria — y por qué Inspira Ranch es el único venue en Livingston construido para este hito.' },

  'blog.post4.title':   { en: 'Planning an Event in Livingston TX? Here\'s What to Look For', es: '¿Planeando un Evento en Livingston TX? Esto Es Lo Que Debes Buscar' },
  'blog.post4.excerpt': { en: 'Not every event space in East Texas is built for serious events. Before you book, know the five things that separate a true private event venue from a rental hall — and see how Inspira Ranch measures up.', es: 'No todo espacio para eventos en el Este de Texas está construido para eventos serios. Antes de reservar, conoce las cinco cosas que separan un verdadero venue privado de un salón de alquiler — y ve cómo Inspira Ranch cumple con cada una.' },

  'post.cta.h3': { en: 'Ready to Host at Inspira Ranch?', es: '¿Listo para Celebrar en Inspira Ranch?' },
  'post.cta.p':  { en: '14 private acres in Livingston, TX. Call +1 (832) 451-5923 or email marketing@konfronta.mx to check your date. We respond within 24 hours.', es: '14 acres privados en Livingston, TX. Llama al +1 (832) 451-5923 o escribe a marketing@konfronta.mx para verificar tu fecha. Respondemos en 24 horas.' },

