  // ── ABOUT PAGE ──────────────────────────────────────────────────────────────
  'about.hero.label': { en: 'OUR STORY', es: 'NUESTRA HISTORIA' },
  'about.hero.h1':    { en: 'Built by Family. Built for You.', es: 'Construido por Familia. Para Ti.' },
  'about.hero.sub':   { en: '14 private acres in Livingston, TX founded on the belief that every gathering deserves to be extraordinary.', es: '14 acres privados en Livingston, TX fundados en la creencia de que cada reunión merece ser extraordinaria.' },

  'about.story.label': { en: 'THE PURPOSE OF INSPIRA RANCH', es: 'EL PROPÓSITO DE INSPIRA RANCH' },
  'about.story.h2':    { en: 'The Name Inspira Is No Coincidence', es: 'El Nombre Inspira No Es Casualidad' },
  'about.story.p1':    { en: 'It has a deep and strategic purpose. The word Inspira is the core of what we seek to achieve: igniting a spark in people, in entrepreneurs, in leaders.', es: 'Tiene un propósito profundo y estratégico. La palabra Inspira es el núcleo de lo que buscamos lograr: encender una chispa en las personas, en los empresarios, en los líderes.' },
  'about.story.p2':    { en: 'It is a call to action from internal motivation. That spirit of yes you can moves you to leave your comfort zone and dare to do more.', es: 'Es un llamado a la acción desde la motivación interna. Ese espíritu de sí puedes te mueve a salir de tu zona de confort y atreverte a hacer más.' },
  'about.story.p3':    { en: 'Founded by Melecio Ortega on 14 private acres in the heart of East Texas, the ranch blends natural beauty with full event infrastructure unlike anything else in the region. What started as a vision became a 5 star rated destination for weddings, quinceañeras, corporate retreats, and transformational conferences.', es: 'Fundado por Melecio Ortega en 14 acres privados en el corazón del Este de Texas, el rancho combina la belleza natural con infraestructura completa de eventos sin igual en la región. Lo que comenzó como una visión se convirtió en un destino de 5 estrellas para bodas, quinceañeras, retiros corporativos y conferencias transformadoras.' },

  'about.team.label': { en: 'THE PEOPLE BEHIND THE RANCH', es: 'LAS PERSONAS DETRÁS DEL RANCHO' },
  'about.team.h2':    { en: 'Meet the Ortega Family', es: 'Conoce a la Familia Ortega' },
  'about.team.sub':   { en: 'Every event at Inspira Ranch is planned, coordinated, and executed by the family that built it. You work directly with us.', es: 'Cada evento en Inspira Ranch es planeado, coordinado y ejecutado por la familia que lo construyó. Trabajas directamente con nosotros.' },

  'about.melecio.name':  { en: 'Melecio Ortega', es: 'Melecio Ortega' },
  'about.melecio.title': { en: 'Founder and President · Konfronta Consulting', es: 'Fundador y Presidente · Konfronta Consulting' },
  'about.melecio.bio':   { en: 'Melecio founded Inspira Ranch and leads the Konfronta Business Conference Series hosted on the property. A business strategist and entrepreneur, he built the ranch as a place where transformation happens for families celebrating milestones and leaders seeking clarity. His keynotes on AI driven growth and sales systems have guided hundreds of business owners across Latin America and the United States.', es: 'Melecio fundó Inspira Ranch y lidera la Serie de Conferencias de Negocios Konfronta alojada en la propiedad. Estratega de negocios y empresario, construyó el rancho como un lugar donde ocurre la transformación para familias que celebran hitos y líderes que buscan claridad. Sus conferencias sobre crecimiento impulsado por IA y sistemas de ventas han guiado a cientos de propietarios de negocios en América Latina y Estados Unidos.' },
  'about.claudia.bio':   { en: 'Claudia coordinates and manages every event at Inspira Ranch end to end. Her hands-on approach ensures that each celebration runs smoothly from first inquiry to final dance.', es: 'Claudia coordina y gestiona cada evento en Inspira Ranch de principio a fin. Su enfoque práctico garantiza que cada celebración se desarrolle sin contratiempos desde la primera consulta hasta el baile final.' },
  'about.bianca.bio':    { en: 'Bianca manages Inspira Ranch digital presence and social media channels, keeping the community connected and the brand growing online. She brings the ranch story to life through content that resonates with families and businesses across Texas and beyond.', es: 'Bianca gestiona la presencia digital de Inspira Ranch y los canales de redes sociales, manteniendo la comunidad conectada y la marca creciendo en línea. Ella da vida a la historia del rancho a través de contenido que resuena con familias y negocios en Texas y más allá.' },
  'about.sebastian.name':  { en: 'Sebastian Ortega', es: 'Sebastian Ortega' },
  'about.sebastian.title': { en: 'Social Media and Online Manager', es: 'Gerente de Redes Sociales y Presencia Digital' },
  'about.sebastian.bio':   { en: 'Sebastian handles online content strategy and digital marketing, growing Inspira Ranch reach across all platforms. His creative approach ensures that every story from the ranch finds its audience.', es: 'Sebastian maneja la estrategia de contenido en línea y el marketing digital, haciendo crecer el alcance de Inspira Ranch en todas las plataformas. Su enfoque creativo asegura que cada historia del rancho encuentre a su audiencia.' },

  'about.val.label': { en: 'WHAT DRIVES US', es: 'LO QUE NOS IMPULSA' },
  'about.val.h2':    { en: 'Our Core Values', es: 'Nuestros Valores Fundamentales' },
  'about.val1.h3':   { en: 'Inspiration Over Routine', es: 'Inspiración Sobre la Rutina' },
  'about.val1.body': { en: 'We do not just host events. We create experiences that challenge and elevate everyone who walks through our gates.', es: 'No solo organizamos eventos. Creamos experiencias que desafían y elevan a todos los que cruzan nuestras puertas.' },
  'about.val2.h3':   { en: 'Family and Community', es: 'Familia y Comunidad' },
  'about.val2.body': { en: 'Family founded, family operated. We treat every client event with the same care we would give our own celebration.', es: 'Fundado por familia, operado por familia. Tratamos cada evento del cliente con el mismo cuidado que daríamos a nuestra propia celebración.' },
  'about.val3.h3':   { en: 'Results Driven', es: 'Orientado a Resultados' },
  'about.val3.body': { en: 'A 5 star rating from every guest we have ever hosted. That record is not an accident. It is the standard we hold ourselves to every single time.', es: 'Una calificación de 5 estrellas de cada huésped que hemos recibido. Ese récord no es un accidente. Es el estándar que nos exigimos cada vez.' },

