  'svc.plata.price': { en: 'Contact for Pricing', es: 'Consultar Precio' },
  'svc.plata.desc':  { en: 'Exclusive property access from 7 AM with the full venue setup including tables, chairs, linens, chapel, security, and private prep room. BYOB available. Perfect for celebrations that bring their own catering and entertainment.', es: 'Acceso exclusivo a la propiedad desde las 7 AM con la configuración completa del venue incluyendo mesas, sillas, manteles, capilla, seguridad y sala de preparación privada. BYOB disponible. Perfecto para celebraciones que traen su propio catering y entretenimiento.' },
