  'svc.bronce.desc':    { en: 'The essential Inspira Ranch venue including hall with tables and chairs, unlimited parking, reheating kitchen, and BYOB. Perfect for intimate gatherings and events with their own full setup.', es: 'El venue esencial de Inspira Ranch que incluye salón con mesas y sillas, estacionamiento ilimitado, cocina de recalentamiento y BYOB. Perfecto para reuniones íntimas y eventos con su propia configuración completa.' },
  'svc.bronce.hdr':     { en: 'Bronze Inclusions',  es: 'Inclusiones Bronce' },
  'svc.bronce.addons':  { en: 'Add ons available: chapel, security, linens, horse and carriage, DJ, catering buffet.', es: 'Complementos disponibles: capilla, seguridad, manteles, caballo y carruaje, DJ, buffet de catering.' },

