  'svc.konfronta.label': { en: 'BUSINESS EVENTS', es: 'EVENTOS DE NEGOCIOS' },
  'svc.konfronta.h2':    { en: 'Retiro Empresarial Konfronta', es: 'Retiro Empresarial Konfronta' },
  'svc.konfronta.body':  { en: 'Inspira Ranch is home to the Konfronta Business Conferences, immersive leadership and business seminars led by founder Melecio Ortega. The ranch setting creates the conditions for real transformation.', es: 'Inspira Ranch es el hogar de las Conferencias de Negocios Konfronta, seminarios de liderazgo y negocios inmersivos dirigidos por el fundador Melecio Ortega. El ambiente del rancho crea las condiciones para una transformación real.' },
  'svc.ksales.h4':       { en: 'Ventas con Inteligencia Artificial', es: 'Ventas con Inteligencia Artificial' },
  'svc.ksales.body':     { en: 'A new paradigm that multiplies your income in a predictable, scalable way using AI driven sales systems.', es: 'Un nuevo paradigma que multiplica tus ingresos de manera predecible y escalable utilizando sistemas de ventas impulsados por IA.' },
  'svc.kmindset.h4':     { en: 'Konfronta Mindset', es: 'Konfronta Mindset' },
  'svc.kmindset.body':   { en: 'Open your mind to see beyond your immediate environment and conquer previously unreachable markets.', es: 'Abre tu mente para ver más allá de tu entorno inmediato y conquistar mercados anteriormente inalcanzables.' },
  'svc.kmodel.label':    { en: 'Methodology', es: 'Metodología' },
  'svc.kmodel.h4':       { en: 'Modelo KonfrontaCultural®', es: 'Modelo KonfrontaCultural®' },
  'svc.kmodel.body':     { en: 'Confront your limiting beliefs, inspire yourself to change, and receive practical tools to apply that transformation in your life and in your company.', es: 'Confronta tus creencias limitantes, inspírate para cambiar y recibe herramientas prácticas para aplicar esa transformación en tu vida y en tu empresa.' },

  'svc.lodge.label': { en: 'LODGING',          es: 'ALOJAMIENTO' },
  'svc.lodge.h2':    { en: 'Stay at the Ranch', es: 'Quédate en el Rancho' },
  'svc.lodge.avail': { en: 'Check Availability', es: 'Verificar Disponibilidad' },

  'svc.casaprincipal.h4':   { en: 'Casa Principal', es: 'Casa Principal' },
  'svc.casaprincipal.body': { en: 'Spacious main house with all amenities for family groups or corporate teams. Sleeps multiple guests with comfort and privacy.', es: 'Casa principal espaciosa con todas las comodidades para grupos familiares o equipos corporativos. Aloja a múltiples huéspedes con confort y privacidad.' },
  'svc.apt.h4':             { en: 'Apartamento', es: 'Apartamento' },
  'svc.apt.body':           { en: 'Private apartment ideal for couples or individual guests seeking peace, privacy, and the beauty of East Texas nature.', es: 'Apartamento privado ideal para parejas o huéspedes individuales que buscan tranquilidad, privacidad y la belleza de la naturaleza del Este de Texas.' },
  'svc.caballeriza.h4':     { en: 'Casa Caballeriza', es: 'Casa Caballeriza' },
  'svc.caballeriza.body':   { en: 'A unique on property structure available for special event needs. Home to the horses used for carriage rides, part of what makes Inspira Ranch unlike any other venue in Texas.', es: 'Una estructura única en la propiedad disponible para necesidades especiales de eventos. Hogar de los caballos utilizados para los paseos en carruaje, parte de lo que hace a Inspira Ranch diferente a cualquier otro venue en Texas.' },
  'svc.juegos.h4':          { en: 'Recreation and Games Area', es: 'Área de Recreación y Juegos' },
  'svc.juegos.body':        { en: 'Dedicated outdoor recreation space for guests to enjoy between events. Lawn games and open air activities across 14 acres of East Texas landscape.', es: 'Espacio dedicado de recreación al aire libre para que los huéspedes disfruten entre eventos. Juegos de jardín y actividades al aire libre en 14 acres del paisaje del Este de Texas.' },

  'svc.cta.label': { en: 'GET A CUSTOM QUOTE',          es: 'OBTENER COTIZACIÓN PERSONALIZADA' },
  'svc.cta.h2':    { en: 'Request Pricing for Your Event', es: 'Solicitar Precios para Tu Evento' },
  'svc.cta.sub':   { en: 'All packages are priced based on your event date, guest count, and selections. Contact us for a custom quote within 24 hours.', es: 'Todos los paquetes tienen precios basados en tu fecha de evento, número de invitados y selecciones. Contáctanos para una cotización personalizada en 24 horas.' },
  'svc.cta.btn':   { en: 'Book Your Event', es: 'Reserva Tu Evento' },

