let currentLang = localStorage.getItem('ir_lang') || 'en';

function applyLang(lang) {
  currentLang = lang;
  document.querySelectorAll('[data-key]').forEach(el => {
    const key = el.getAttribute('data-key');
    if (translations[key] && translations[key][lang]) {
      el.textContent = translations[key][lang];
    }
  });
  document.querySelectorAll('[data-key-placeholder]').forEach(el => {
    const key = el.getAttribute('data-key-placeholder');
    const t = translations[key];
    if (t && t[lang]) el.placeholder = t[lang];
  });
  // Legacy CSS class system for pages using .lang.en / .lang.es spans
  document.body.classList.remove('show-en', 'show-es');
  document.body.classList.add('show-' + lang);
  // System 3: dictionary i18n — text nodes, attributes, document title
  translateTextNodes(lang);
  translateAttrs(lang);
  translateDocTitle(lang);
  const btn = document.getElementById('langBtn');
  if (btn) btn.textContent = lang === 'en' ? '🌐 Español' : '🌐 English';
  document.documentElement.lang = lang;
  localStorage.setItem('ir_lang', lang);
}

// ════ System 3: dictionary i18n for everything not covered by data-key or .lang spans ════
// textI18n / attrI18n / titleI18n dictionaries are defined at the bottom of this file.
const I18N_ATTRS = ['placeholder', 'alt', 'aria-label', 'title'];
